const gcd = (a, b) => {
    a = Math.abs(a);
    b = Math.abs(b);
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
};

/**
 * Segment Tree implementation for Range GCD Queries and Point Updates.
 * Stores GCD of normalized elements (nums[i]/p) or 0 if not divisible by p.
 */
class SegmentTree {
    constructor(arr, N, P) {
        this.N = N;
        this.P = P;
        // Size 4*N is safe
        this.tree = new Array(4 * N).fill(0);
        this.arr = arr.map((val, i) => {
            return (P > 0 && val % P === 0) ? val / P : 0;
        });
        this.build(0, 0, N - 1);
    }

    build(node, start, end) {
        if (start === end) {
            this.tree[node] = this.arr[start];
            return;
        }
        const mid = Math.floor((start + end) / 2);
        this.build(2 * node + 1, start, mid);
        this.build(2 * node + 2, mid + 1, end);
        this.tree[node] = gcd(this.tree[2 * node + 1], this.tree[2 * node + 2]);
    }

    update(idx, val) {
        const newNormalizedVal = (this.P > 0 && val % this.P === 0) ? val / this.P : 0;
        this.arr[idx] = newNormalizedVal;
        this._update(0, 0, this.N - 1, idx, newNormalizedVal);
    }

    _update(node, start, end, idx, newNormalizedVal) {
        if (start === end) {
            this.tree[node] = newNormalizedVal;
            return;
        }
        const mid = Math.floor((start + end) / 2);
        if (idx <= mid) {
            this._update(2 * node + 1, start, mid, idx, newNormalizedVal);
        } else {
            this._update(2 * node + 2, mid + 1, end, idx, newNormalizedVal);
        }
        this.tree[node] = gcd(this.tree[2 * node + 1], this.tree[2 * node + 2]);
    }

    query(l, r) {
        return this._query(0, 0, this.N - 1, l, r);
    }

    _query(node, start, end, l, r) {
        if (r < start || end < l) {
            // Identity element for GCD is 0 since gcd(x, 0) = x
            return 0;
        }
        if (l <= start && end <= r) {
            return this.tree[node];
        }
        const mid = Math.floor((start + end) / 2);
        const p1 = this._query(2 * node + 1, start, mid, l, r);
        const p2 = this._query(2 * node + 2, mid + 1, end, l, r);
        return gcd(p1, p2);
    }
}


function solve(nums, p, queries) {
    const N = nums.length;
    if (N < 2) return 0; // Constraint N >= 2, but good practice

    // 1. Initialize state tracking
    let count_N_P = 0; // Counter for |N_P|: count of elements divisible by P
    const st = new SegmentTree(nums, N, p);

    for(let i = 0; i < N; i++) {
        if (nums[i] % p === 0) {
            count_N_P++;
        }
    }

    let result_count = 0;

    for (const [idx, val_new] of queries) {
        const old_val = nums[idx];

        // --- Update count_N_P ---

        // Check if old value contributed to N_P
        const was_divisible = (p > 0 && old_val % p === 0);
        if (was_divisible) {
            count_N_P--;
        }

        // Check if new value contributes to N_P
        const will_be_divisible = (p > 0 && val_new % p === 0);
        if (will_be_divisible) {
            count_N_P++;
        }

        // --- Update nums and Segment Tree ---
        nums[idx] = val_new;
        st.update(idx, val_new);

        // --- Check for Good Subsequence Existence ---

        let exists_good_subsequence = false;

        if (count_N_P === 0) {
            exists_good_subsequence = false;
        } else {
            // Get G = GCD(N'_P)
            const G = st.query(0, N - 1);

            if (G === 1) {
                if (count_N_P < N) {
                    // Case 1: Not all elements are multiples of P. If GCD=1, a good subsequence exists.
                    exists_good_subsequence = true;
                } else {
                    // Case 2: All N elements are multiples of P (count_N_P == N).

                    if (N === 2) {
                        // Must find a subsequence of length 1. Requires one element to be P.
                        const a0 = nums[0] / p;
                        const a1 = nums[1] / p;
                        if (a0 === 1 || a1 === 1) {
                            exists_good_subsequence = true;
                        }
                    } else { 
                        // Case 2b: N >= 3. If GCD=1, a proper subsequence S' with GCD=1 is guaranteed 
                        // given the constraints on V_max (5*10^4).
                        exists_good_subsequence = true;
                    }
                }
            }
        }

        if (exists_good_subsequence) {
            result_count++;
        }
    }

    return result_count;
}

